const gravatarUrl=(email,s)=>"https://www.gravatar.com/avatar/"+md5(String(email||"").trim().toLowerCase())+"?s="+s+"&d=404";
const initialsOf=(name,email)=>{ if(name&&name.trim()){const p=name.trim().split(/\s+/);return ((p[0][0]||"")+(p[1]?p[1][0]:"")).toUpperCase();} if(email)return email.slice(0,2).toUpperCase(); return "PX"; };
function Avatar({ email, name, size=34, radius=9, style }){
  const [err,setErr]=useState(false);
  useEffect(()=>{setErr(false);},[email]);
  const common={width:size,height:size,borderRadius:radius,flexShrink:0,...style};
  if(!email||err) return <div style={{...common,background:"var(--ai)",color:"#fff",display:"grid",placeItems:"center",fontFamily:"'JetBrains Mono',monospace",fontWeight:700,fontSize:Math.round(size*0.38)}}>{initialsOf(name,email)}</div>;
  return <img src={gravatarUrl(email,Math.round(size*2))} onError={()=>setErr(true)} alt="" referrerPolicy="no-referrer" style={{...common,objectFit:"cover",display:"block"}}/>;
}
function Tip({active,payload,label}){if(!active||!payload||!payload.length)return null;return <div className="tt"><div className="k">{label}</div>{payload.filter(p=>p.value!=null).map((p,i)=><div key={i} className="v" style={{color:p.color||p.stroke}}>{fmt0(p.value)}</div>)}</div>;}

