/* ================================================================== */
/*  AUTH (login / register)                                           */
/* ================================================================== */
function AuthPage({ mode, dark, toggleTheme, go, setUser, cfg }){
  const isReg=mode==="register";
  const AU=(cfg&&cfg.auth)||{};
  const modeOK=isReg?AU.register!==false:AU.login!==false;
  const [email,setEmail]=useState("");
  const [pw,setPw]=useState("");
  const [name,setName]=useState("");
  const [show,setShow]=useState(false);
  const [remember,setRemember]=useState(true);
  const valid=email.includes("@")&&pw.length>=4&&(!isReg||name.trim());
  const enter=()=>{
    api.auth(isReg?"register":"login",{email,password:pw,name}).then(res=>{
      if(setUser&&email) setUser(u=>({name:(res&&res.user&&res.user.name)||(isReg&&name.trim()?name.trim():u.name),email}));
    });
    if(setUser&&email) setUser(u=>({name:isReg&&name.trim()?name.trim():u.name,email}));
    go("app");
  };
  return (
    <div className="scr fade">
      <div className="auth-split">
        <aside className="auth-aside auth-brand">
          <div className="brand-mesh"/>
          <div className="brand-grid"/>
          <div className="logo" style={{position:"relative",zIndex:2}}>
            <LogoMark size={30}/>
            <div className="logo-tx" style={{color:"#fff"}}>Pix<span style={{color:"#fff",opacity:.8}}>ii</span></div>
          </div>
          <div style={{position:"relative",zIndex:2}}>
            <h2 className="brand-h">The autonomous<br/>finance OS.</h2>
            <p className="brand-p">Sign in to your cockpit — forecasts, autonomous agents and a copilot that actually understands your money.</p>
            <div className="brand-feats">
              {[[Bot,"AI copilot at your command"],[Activity,"Forecast your net worth"],[ShieldCheck,"Bank-grade & read-only"]].map(([Ic,t],i)=>(
                <div className="brand-feat" key={i}><Ic size={16}/><span>{t}</span></div>
              ))}
            </div>
          </div>
          <div className="brand-cards">
            <div className="gcard">
              <div className="gc-l">NET WORTH</div>
              <div className="gc-v">$53,216</div>
              <div className="gc-d">&#9650; 3.1% this month</div>
              <svg viewBox="0 0 120 30" preserveAspectRatio="none" className="gc-spark"><polyline points="0,26 22,20 44,22 66,12 88,15 120,4" fill="none" stroke="#fff" strokeWidth="2"/></svg>
            </div>
            <div className="gcard sm">
              <div className="gc-l">RUNWAY</div>
              <div className="gc-v" style={{fontSize:24}}>8.1<span style={{fontSize:12,opacity:.7}}> mo</span></div>
              <div className="gc-d">healthy buffer</div>
            </div>
          </div>
          <div className="brand-trust" style={{position:"relative",zIndex:2}}>
            <span>SOC 2</span><span>&middot;</span><span>256-bit encryption</span><span>&middot;</span><span>Plaid</span>
          </div>
        </aside>

        <main className="auth-main">
          <div className="auth-card">
            <div className="auth-top">
              <span className="auth-back" onClick={()=>go("landing")}><ArrowRight size={14} style={{transform:"rotate(180deg)"}}/> Back to home</span>
              <button className="icobtn" onClick={toggleTheme}>{dark?<Sun size={15}/>:<Moon size={15}/>}</button>
            </div>
            <div className="logo" style={{marginBottom:24}}>
              <LogoMark size={30}/><div className="logo-tx">Pix<span>ii</span></div>
            </div>
            <h2>{isReg?"Create your account":"Welcome back"}</h2>
            <div className="lead">{isReg?"Start managing money like it's the 22nd century.":"Sign in to pick up right where you left off."}</div>

            {isReg && <div className="field"><label className="flab">Full name</label><div className="ipwrap"><User size={16} color="var(--ink-3)"/><input value={name} onChange={e=>setName(e.target.value)} placeholder="Jordan Reyes"/></div></div>}
            <div className="field"><label className="flab">Email</label><div className="ipwrap"><Mail size={16} color="var(--ink-3)"/><input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="you@email.com"/></div></div>
            <div className="field"><label className="flab">Password</label>
              <div className="ipwrap"><Lock size={16} color="var(--ink-3)"/>
                <input type={show?"text":"password"} value={pw} onChange={e=>setPw(e.target.value)} placeholder={"\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022"}/>
                <button className="pw-toggle" onClick={()=>setShow(s=>!s)} tabIndex={-1}>{show?<EyeOff size={15}/>:<Eye size={15}/>}</button>
              </div>
            </div>

            <div className="auth-row">
              <label className="rmbr" onClick={()=>setRemember(r=>!r)}><span className={"cbox sm"+(remember?" on":"")}>{remember&&<Check size={11}/>}</span>Remember me</label>
              {!isReg && <span className="flink">Forgot password?</span>}
            </div>

            {!modeOK && <div className="auth-disabled"><Lock size={13}/> {isReg?"New sign-ups are currently disabled by an administrator.":"Sign-in is temporarily disabled by an administrator."}</div>}
            <button className="btn pri" style={{width:"100%",justifyContent:"center",padding:"12px"}} disabled={!valid||!modeOK} onClick={enter}>{isReg?"Create account":"Sign in"} <ArrowRight size={16}/></button>

            <div className="divider-or">or continue with</div>
            <div className="soc-row">
              {AU.google!==false && <button className="soc-btn" onClick={()=>go("app")}><GoogleG/> Google</button>}
              {AU.apple!==false && <button className="soc-btn" onClick={()=>go("app")}><AppleLogo/> Apple</button>}
            </div>
            {AU.passkey!==false && <button className="soc-btn wide" onClick={()=>go("app")}><Fingerprint size={16}/> Use a passkey</button>}

            <div className="auth-switch">
              {isReg?<>Already have an account? <span className="flink" onClick={()=>go("login")}>Sign in</span></>
                    :<>New to Pixii? <span className="flink" onClick={()=>go("register")}>Create a free account</span></>}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
function GoogleG(){return (<svg width="16" height="16" viewBox="0 0 48 48" aria-hidden="true"><path fill="#EA4335" d="M24 9.5c3.5 0 6.6 1.2 9 3.6l6.8-6.8C35.6 2.4 30.1 0 24 0 14.6 0 6.5 5.4 2.6 13.2l7.9 6.1C12.4 13.1 17.7 9.5 24 9.5z"/><path fill="#4285F4" d="M46.1 24.6c0-1.6-.1-3.1-.4-4.6H24v9.3h12.4c-.5 2.9-2.1 5.3-4.6 7l7.1 5.5c4.2-3.9 6.6-9.6 6.6-16.2z"/><path fill="#FBBC05" d="M10.5 28.3c-.5-1.4-.8-2.9-.8-4.3s.3-3 .8-4.3l-7.9-6.1C.9 16.5 0 20.1 0 24s.9 7.5 2.6 10.4l7.9-6.1z"/><path fill="#34A853" d="M24 48c6.1 0 11.3-2 15-5.5l-7.1-5.5c-2 1.3-4.6 2.1-7.9 2.1-6.3 0-11.6-3.6-13.5-9.3l-7.9 6.1C6.5 42.6 14.6 48 24 48z"/></svg>);}
function AppleLogo(){return (<svg width="15" height="16" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M16.36 12.84c.02 2.3 2 3.07 2.05 3.09-.02.05-.32 1.1-1.05 2.18-.63.94-1.29 1.87-2.33 1.89-1.02.02-1.35-.6-2.51-.6-1.17 0-1.53.58-2.5.62-1 .04-1.77-1.01-2.41-1.95-1.3-1.9-2.3-5.36-.96-7.7.66-1.16 1.85-1.9 3.14-1.92.99-.02 1.93.67 2.53.67.6 0 1.74-.83 2.94-.71.5.02 1.9.2 2.8 1.53-.07.05-1.67.98-1.65 2.91M14.5 4.7c.53-.64.89-1.53.79-2.42-.76.03-1.69.51-2.24 1.15-.49.56-.92 1.47-.8 2.33.85.07 1.71-.43 2.25-1.06"/></svg>);}
function WorkOSMark({ size=16 }){return (<svg width={size} height={size} viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M2.6 6.6 6.7 12l-4.1 5.4h3.3L13.3 12 5.9 6.6H2.6Z" fill="currentColor"/><path d="M10.7 6.6 14.8 12l-4.1 5.4H14L21.4 12 14 6.6h-3.3Z" fill="currentColor" opacity=".5"/></svg>);}

function SsoModal({ onClose, onAuth }){
  const [step,setStep]=useState(0);
  const [email,setEmail]=useState("");
  const domain=email.includes("@")?email.split("@")[1].toLowerCase():"";
  const idp=/google|gmail|gworkspace/.test(domain)?"Google Workspace":/microsoft|outlook|azure/.test(domain)?"Microsoft Entra ID":"Okta";
  const valid=email.includes("@")&&domain.includes(".");
  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div className="wos-head"><span className="wos-badge"><WorkOSMark size={15}/> WorkOS</span><button className="icobtn" onClick={onClose} style={{border:"none",background:"none"}}><X size={16}/></button></div>
        {step===0 && (
          <div style={{padding:"6px 22px 22px"}}>
            <div className="wos-key"><KeyRound size={20}/></div>
            <h3 style={{fontSize:19,fontWeight:700,margin:"4px 0 4px"}}>Single sign-on</h3>
            <p style={{fontSize:13.5,color:"var(--ink-2)",lineHeight:1.5,margin:"0 0 16px"}}>Enter your work email and we'll route you to your organization's identity provider.</p>
            <div className="field"><label className="flab">Work email</label><div className="ipwrap"><Mail size={16} color="var(--ink-3)"/><input type="email" autoFocus value={email} onChange={e=>setEmail(e.target.value)} placeholder="you@company.com"/></div></div>
            <button className="btn pri" style={{width:"100%",justifyContent:"center",padding:"11px",marginTop:6}} disabled={!valid} onClick={()=>setStep(1)}>Continue <ArrowRight size={15}/></button>
          </div>
        )}
        {step===1 && (
          <div style={{padding:"6px 22px 22px"}}>
            <div className="wos-prov"><span className="wos-dot">{idp[0]}</span><div><div style={{fontWeight:700,fontSize:14}}>{idp}</div><div style={{fontSize:11.5,color:"var(--ink-3)",fontFamily:"'JetBrains Mono',monospace"}}>SAML 2.0 · {domain}</div></div><span className="recon ok" style={{marginLeft:"auto"}}><CheckCircle2 size={11} style={{verticalAlign:"-2px"}}/> SSO found</span></div>
            <p style={{fontSize:13,color:"var(--ink-2)",lineHeight:1.5,margin:"14px 0 16px"}}>You'll be securely redirected to <b style={{color:"var(--ink)"}}>{idp}</b> to authenticate, then returned to Pixii.</p>
            <button className="btn pri" style={{width:"100%",justifyContent:"center",padding:"11px"}} onClick={()=>onAuth(email)}>Continue to {idp} <ArrowRight size={15}/></button>
            <button className="btn ghost sm" style={{width:"100%",justifyContent:"center",marginTop:8}} onClick={()=>setStep(0)}>Use a different email</button>
          </div>
        )}
        <div className="wos-foot"><Lock size={11}/> Enterprise SSO secured by <b>WorkOS</b></div>
      </div>
    </div>
  );
}

